<template>
	<view>
		<view class="goods-template">
			<scroll-view scroll-y style="height: 100%;width: 100%;background-color: #f5f7fa;"
				@scrolltolower="reachBottom">

				<view class="list">
					<view class="item" v-for="(item,index) in list" :key="index" @click="goDetail(item)">
						<view class="header">
							<image class="img" v-if="item.img" :src="item.img" mode="aspectFit"></image>
							<view class="name">
								<view class="text" :style="{
									color:item.color
								}">
									{{item.title}}
								</view>
								<view class="time">
									{{ $util.timeFormat(item.create_time,'yyyy-mm-dd hh:MM:ss') }}
								</view>
							</view>
						</view>
						<view class="title">
							{{type == 2 ?item.content:''}}
						</view>
						<!-- <view class="content">
							<u-parse :html="item.content"></u-parse>
						</view> -->

					</view>
				</view>
				<u-loadmore :status="status" margin-top="10" icon-type="circle" v-if="list.length >0 && loaded" />
				<u-empty margin-top="80" v-if="loaded &&  list.length == 0"></u-empty>
			</scroll-view>
		</view>


	</view>
</template>

<script>
	export default {
		data() {
			return {
				activeColor: '#f06c7a',
				inactiveColor: '#606266',
				list: [],
				type: 0,
				status: 'loadmore',
				iconType: 'flower',
				loadText: {
					loadmore: '上拉加载',
					loading: '努力加载中',
					nomore: '实在没有了'
				},
				page: 1,
				limit: 10,

				id: 0,
				loaded: false,
				title: '',
			};
		},
		onLoad(e) {

			if (e.type) {
				this.type = e.type
			} else {
				this.type = 1
			}


			if (e.title) {
				this.title = e.title
				uni.setNavigationBarTitle({
					title: this.title
				})
			}
			if (e.id) {
				this.id = e.id

			}

			// switch (this.type) {
			// 	case '1':
			// 		this.title = '平台系统公告'
			// 		break;
			// 	case '2':
			// 		this.title = '平台站内短信'
			// 		break;
			// 	case '3':
			// 		this.title = '商品宣传文案'
			// 		break;
			// 	default:


			// }



			this.loadData();

		},
		methods: {
			reachBottom() {
				console.log(123);

				setTimeout(() => {
					this.loadData();
				}, 200);

			},
			async loadData() {

				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				this.$u.api.noticeList({
						type: this.type,
						page: this.page,
						limit: this.limit,
						id: this.id,
					})
					.then(res => {

						if (res.data.length == 0) {
							this.status = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.data)
							} else {
								this.list = res.data
							}

							this.page++;
							if (this.limit > res.data.length) {
								this.status = 'nomore'
							} else {
								this.status = 'loadmore'
							}


						}
						this.loaded = true


					}).catch(res => {})
				uni.hideLoading()
			},
			goDetail(item) {
				if (item.is_link) {
					this.$util.on(item.url)
				} else {
					this.$util.on('/pages/msg_sub/msgDetail?id=' + item.id + '&type=' + this.type)
				}
			}
		}
	}
</script>

<style lang="scss" scoped>
	page {
		background-color: #f5f7fa;
		height: 100%;
	}

	.goods-template {
		width: 100%;
		height: 100%;
		// position: fixed;
		top: 0;
		left: 0;
		overflow: hidden;
	}

	.list {
		width: 100%;
		display: flex;
		flex-direction: column;
		align-items: center;
		justify-content: flex-start;
		gap: 16rpx;
		margin-top: 20rpx;
	}

	.list .item {
		display: flex;
		flex-direction: column;
		align-items: center;
		justify-content: flex-start;
		width: 714rpx;
		border-radius: 10rpx;
		background: #FFFFFF;
		padding: 30rpx 20rpx;
		box-sizing: border-box;
	}

	.list .item .header {
		width: 100%;
		display: flex;
		align-items: flex-start;
		justify-content: flex-start;
		gap: 20rpx;
	}

	.list .item .header .img {
		width: 88rpx;
		height: 88rpx;
		border-radius: 50%;
	}

	.list .item .header .name {
		flex: 1;
		height: 80rpx;
		display: flex;
		flex-direction: column;
		justify-content: space-between;
		align-items: flex-start;
	}

	.list .item .title {
		width: 100%;
		font-size: 30rpx;
		font-family: PingFangSC-Medium, PingFang SC;
		font-weight: 500;
		color: #1e2331;
		margin-top: 24rpx;
		white-space: pre-line;
	}

	.list .item .header .name .text {
		font-size: 28rpx;
		font-family: PingFangSC-Medium, PingFang SC;
		font-weight: 500;
		color: #1e2331;
	}

	.list .item .header .name .time {
		font-size: 24rpx;
		font-family: PingFangSC-Regular, PingFang SC;
		font-weight: 400;
		color: #9b9fa8;
	}
</style>